mapper.select:
SELECT id , name , chartType , albumId , url , size , trackCount , createDateTime , updateDateTime , registDateTime , playTime , playListType , dispSn , likeUpdateDtime , renewDateTime , renewTrackCnt FROM ( SELECT CL.CHART_ID AS id , CL.CHART_NM AS name , CL.CHART_TYPE AS chartType , CL.ALBUM_ID AS albumId , I.URL AS url , I.SIZE AS size , CL.MUSIC_CONTENT_CNT AS trackCount , CL.CREATE_DTIME AS createDateTime , CL.UPDATE_DTIME AS updateDateTime , null AS registDateTime , '' AS playTime , CL.LIKE_TYPE AS playListType , CL.DISP_SN AS dispSn , CL.UPDATE_DTIME AS likeUpdateDtime , null AS renewDateTime , '' AS renewTrackCnt FROM ( SELECT A.CHART_ID , A.CHART_NM , A.CHART_TYPE , C.ALBUM_ID , A.MUSIC_CONTENT_CNT , A.CREATE_DTIME , A.UPDATE_DTIME , CASE WHEN A.CHART_TYPE = 'NEW' THEN 'CHART' ELSE 'RANK_CHART' END AS LIKE_TYPE , L.DISP_SN , L.UPDATE_DTIME AS LIKE_UPDATE_DTIME FROM ( SELECT LIKE_TYPE_ID , LIKE_TYPE , DISP_SN , UPDATE_DTIME FROM TB_CHARACTER_LIKE WHERE CHARACTER_NO = #{characterNo}
AND LIKE_TYPE_ID IN
#{chartId}
AND 1 = 0
AND LIKE_TYPE = 'CHART') L INNER JOIN TB_CHART A ON L.LIKE_TYPE_ID = A.CHART_ID INNER JOIN TB_CHART_MUSIC_CONTENT B ON A.CHART_ID = B.CHART_ID AND B.DISP_SN = 1 INNER JOIN TB_TRACK C ON B.MUSIC_CONTENT_ID = C.TRACK_ID ) CL INNER JOIN TED_ALBUMIMAGE I ON CL.ALBUM_ID = I.ALBUM_ID UNION ALL SELECT A.CHNL_ID AS id , A.CHNL_NM AS name , '' AS chartType , '' AS albumId , I.ALBUM_IMG_URL AS url , I.ALBUM_IMG_SIZE AS size , A.TRACK_CNT AS trackCount , A.CREATE_DTIME AS createDateTime , A.UPDATE_DTIME AS updateDateTime , A.ES_ALBUM_APPLY_DTIME AS registDateTime , A.CHNL_PLAY_TM AS playTime , IF(A.CHNL_TYPE !='FLAC', IF(A.CHNL_TYPE !='AFLO', 'CHNL', 'AFLO'), 'FLAC') AS playListType , L.DISP_SN AS dispSn , L.UPDATE_DTIME AS likeUpdateDtime , A.RENEW_DTIME AS renewDateTime , A.RENEW_TRACK_CNT AS renewTrackCnt FROM ( SELECT LIKE_TYPE_ID , LIKE_TYPE , DISP_SN , UPDATE_DTIME FROM TB_CHARACTER_LIKE WHERE CHARACTER_NO = #{characterNo}
AND LIKE_TYPE_ID IN
#{chnlId}
AND 1 = 0
AND LIKE_TYPE = 'CHNL') L INNER JOIN TB_CHNL A ON L.LIKE_TYPE_ID = A.CHNL_ID AND A.DISP_STATUS_TYPE = 'Y' AND A.CHNL_TYPE !='AFLO'
AND A.CHNL_TYPE !='FLAC'
INNER JOIN TB_ALBUM_IMG I ON A.ALBUM_ID = I.ALBUM_ID
UNION ALL SELECT A.chnl_id AS id , A.chnl_nm AS name , '' AS chartType , '' AS albumId , I.img_url AS url , 600 AS size , A.track_cnt AS trackCount , A.create_dtime AS createDateTime , A.update_dtime AS updateDateTime , A.es_album_apply_dtime AS registDateTime , A.chnl_play_tm AS playTime , A.chnl_type AS playListType , L.disp_sn AS dispSn , L.update_dtime AS likeUpdateDtime , A.renew_dtime AS renewDateTime , A.renew_track_cnt AS renewTrackCnt FROM ( SELECT like_type_id , like_type , disp_sn , update_dtime FROM tb_character_like WHERE character_no = #{characterNo}
AND like_type_id IN
#{chnlId}
AND 1 = 0
AND like_type = 'CHNL') L INNER JOIN tb_chnl A ON L.like_type_id = A.chnl_id AND A.disp_status_type = 'Y' AND A.chnl_type ='AFLO'
INNER JOIN tb_chnl_img I ON A.chnl_id = I.chnl_id AND I.chnl_img_type = 'TOP_DETAIL'
) AA ORDER BY AA.DISPSN ASC, AA.LIKEUPDATEDTIME ASC

SELECT
    COUNT(*)
FROM TB_CHARACTER_LIKE
WHERE CHARACTER_NO = #{characterNo}
      AND LIKE_TYPE = #{likeType}
      AND LIKE_TYPE_ID = #{likeTypeId}

mapper.update:
UPDATE TB_CHARACTER_LIKE
SET DISP_SN = DISP_SN + 1
WHERE CHARACTER_NO = #{characterNo}

mapper.delete:
DELETE FROM TB_CHARACTER_LIKE
WHERE CHARACTER_NO = #{characterNo}
      AND LIKE_TYPE = #{likeType}
      AND LIKE_TYPE_ID = #{likeTypeId}

mapper.update:
UPDATE TB_CHARACTER_LIKE
SET DISP_SN      = #{dispSn}
    , UPDATE_DTIME = now()
WHERE CHARACTER_NO = #{characterNo}
      AND LIKE_TYPE = #{likeType}
      AND LIKE_TYPE_ID = #{likeTypeId}

mapper.insert:
INSERT INTO
  tb_character_like (character_no, like_type, like_type_id, disp_sn)
SELECT #{toCharacterNo}, like_type, like_type_id, disp_sn from tb_character_like where character_no = #{fromCharacterNo}
